/**
 * Viewport State Slice
 *
 * External store for camera/viewport state using @zazcart/tools.
 * Solves the "stale closure" problem in animation loops by using
 * useSyncExternalStore instead of React useState.
 *
 * Benefits:
 * - State reads are synchronous (no batching delay)
 * - Animation loops always see current values
 * - No more cameraPosRef workaround needed
 *
 * @see TECH-DEBT-001
 * @see CLAUDE.md "React Hooks vs External Stores"
 */

import { createSyncSlice } from '@zazcart/tools';

// ─────────────────────────────────────────────────────────────
// STATE TYPES
// ─────────────────────────────────────────────────────────────

export interface CameraPosition {
  x: number;
  y: number;
}

export interface MomentumState {
  velocityX: number;
  velocityY: number;
  isActive: boolean;
}

export interface AnimationState {
  isAnimating: boolean;
  startTime: number;
  duration: number;
  startX: number;
  startY: number;
  startZoom: number;
  targetX: number;
  targetY: number;
  targetZoom: number;
}

export interface CanvasSize {
  width: number;
  height: number;
}

export interface ViewportSliceState {
  // Camera position in world coordinates
  camera: CameraPosition;

  // Canvas dimensions (from R3F)
  canvasSize: CanvasSize;

  // Initialization flag
  isInitialized: boolean;

  // Momentum for inertial panning
  momentum: MomentumState;

  // Smooth animation state
  animation: AnimationState;

  // Interaction state
  isPanning: boolean;
  panStart: CameraPosition;
  cameraPosAtPanStart: CameraPosition;
}

// ─────────────────────────────────────────────────────────────
// INITIAL STATE
// ─────────────────────────────────────────────────────────────

const initialState: ViewportSliceState = {
  camera: { x: 0, y: 0 },
  canvasSize: { width: 800, height: 600 },
  isInitialized: false,
  momentum: {
    velocityX: 0,
    velocityY: 0,
    isActive: false,
  },
  animation: {
    isAnimating: false,
    startTime: 0,
    duration: 250,
    startX: 0,
    startY: 0,
    startZoom: 1,
    targetX: 0,
    targetY: 0,
    targetZoom: 1,
  },
  isPanning: false,
  panStart: { x: 0, y: 0 },
  cameraPosAtPanStart: { x: 0, y: 0 },
};

// ─────────────────────────────────────────────────────────────
// VIEWPORT SLICE
// ─────────────────────────────────────────────────────────────

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const viewportSlice = createSyncSlice({
  id: 'viewport',
  initial: initialState as any,  // TECH-DEBT-002: @zazcart/tools generic inference
  cache: { policy: 'session' },  // Session-scoped: resets when app closes
  reducers: {
    // Camera position
    setCamera(state: any, payload: CameraPosition) {
      (state as ViewportSliceState).camera = payload;
    },

    setCameraX(state: any, payload: number) {
      (state as ViewportSliceState).camera.x = payload;
    },

    setCameraY(state: any, payload: number) {
      (state as ViewportSliceState).camera.y = payload;
    },

    // Canvas size
    setCanvasSize(state: any, payload: CanvasSize) {
      (state as ViewportSliceState).canvasSize = payload;
    },

    // Initialization
    initialize(
      state: any,
      payload: { camera: CameraPosition; canvasSize: CanvasSize }
    ) {
      const s = state as ViewportSliceState;
      s.camera = payload.camera;
      s.canvasSize = payload.canvasSize;
      s.isInitialized = true;
    },

    // Momentum
    setMomentum(state: any, payload: MomentumState) {
      (state as ViewportSliceState).momentum = payload;
    },

    startMomentum(
      state: any,
      payload: { velocityX: number; velocityY: number }
    ) {
      (state as ViewportSliceState).momentum = {
        velocityX: payload.velocityX,
        velocityY: payload.velocityY,
        isActive: true,
      };
    },

    updateMomentum(
      state: any,
      payload: { velocityX: number; velocityY: number; camera: CameraPosition }
    ) {
      const s = state as ViewportSliceState;
      s.momentum.velocityX = payload.velocityX;
      s.momentum.velocityY = payload.velocityY;
      s.camera = payload.camera;
    },

    stopMomentum(state: any) {
      (state as ViewportSliceState).momentum = {
        velocityX: 0,
        velocityY: 0,
        isActive: false,
      };
    },

    // Animation
    startAnimation(
      state: any,
      payload: {
        startX: number;
        startY: number;
        startZoom: number;
        targetX: number;
        targetY: number;
        targetZoom: number;
        duration?: number;
      }
    ) {
      (state as ViewportSliceState).animation = {
        isAnimating: true,
        startTime: Date.now(),
        duration: payload.duration ?? 250,
        startX: payload.startX,
        startY: payload.startY,
        startZoom: payload.startZoom,
        targetX: payload.targetX,
        targetY: payload.targetY,
        targetZoom: payload.targetZoom,
      };
    },

    updateAnimation(
      state: any,
      payload: { camera: CameraPosition }
    ) {
      (state as ViewportSliceState).camera = payload.camera;
    },

    stopAnimation(state: any) {
      (state as ViewportSliceState).animation.isAnimating = false;
    },

    // Panning
    startPan(
      state: any,
      payload: { panStart: CameraPosition; cameraPosAtPanStart: CameraPosition }
    ) {
      const s = state as ViewportSliceState;
      s.isPanning = true;
      s.panStart = payload.panStart;
      s.cameraPosAtPanStart = payload.cameraPosAtPanStart;
    },

    updatePan(state: any, payload: { camera: CameraPosition }) {
      (state as ViewportSliceState).camera = payload.camera;
    },

    endPan(state: any) {
      (state as ViewportSliceState).isPanning = false;
    },

    // Reset
    reset() {
      return initialState;
    },
  },
});

export type ViewportSlice = typeof viewportSlice;

